   139→
   140→	authenticators := 0
   141→	if c.ManagedIdentity != nil {
   142→		authenticators++
   143→	}
   144→	if c.WorkloadIdentity != nil {
   145→		authenticators++
   146→	}
   147→	if c.OAuth != nil {
   148→		authenticators++
